def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(from_pos, to_pos, speed):
        return np.linalg.norm(to_pos - from_pos) / speed

    best_node = None
    min_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        if customer is None:
            continue
        travel_time = calculate_travel_time(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        # Score based on wait time if early, penalty if late, and inverse of the time window width to prioritize narrower windows
        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        if arrival_time > end_window:
            penalty_time = arrival_time - end_window
        else:
            penalty_time = 0

        score = wait_time * 0.1 + penalty_time * 2 + travel_time  # Weigh penalties more than wait time

        if score < min_score:
            min_score = score
            best_node = i

    return best_node

