import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def urgency_score(distance, current_time, time_window):
        start, end = time_window
        if current_time + (distance / truck_speed) < start:
            # high urgency if waiting time is needed
            return (start - current_time - (distance / truck_speed))**2
        elif current_time + (distance / truck_speed) > end:
            # extreme urgency if outside time window
            return float('inf')
        else:
            # lower urgency, can reach within window
            return distance / truck_speed

    urgency_scores = []

    for index, customer in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer)
        score = urgency_score(distance, current_time, time_windows[index])
        urgency_scores.append(score)

    best_node_index = np.argmin(urgency_scores)
    best_node = best_node_index if urgency_scores[best_node_index] != float('inf') else None

    return best_node
